=Analyze the following text and extract long-term facts/entity profiles. Return a JSON object with a single key 'facts' containing a JSON array of facts, each representing a single key entity statement:
{
  "facts": [
    {
      "entity_name": "Name of person, organization, tech stack, or core concept",
      "entity_type": "person or organization or technology or concept",
      "fact_details": "Clean, static summary of the long term fact or insight learned",
      "confidence": 0.95
    }
  ]
}

Content:
{{ $json.cleaned_content }}

=Analyze the following text and extract time-bound events, interactions, decisions, or outcomes. Return a JSON object with a single key 'events' containing a JSON array of events:
{
  "events": [
    {
      "event_name": "Action-oriented description of the event",
      "event_description": "Detailed context of what happened",
      "event_timestamp": "ISO 8601 date-time string if available, otherwise null",
      "actors": ["Name of people or entities involved"],
      "outcome": "The result, decision, or output of this event"
    }
  ]
}

Content:
{{ $json.cleaned_content }}

parameters.jsCode:
const results = [];
const items = $input.all();
for (const item of items) {
  const parent = $('Get Unprocessed Staging').json;
  const responseText = item.json.response || item.json.content || '{}';
  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch(e) {
    parsed = { facts: [] };
  }
  if (parsed.facts && Array.isArray(parsed.facts)) {
    for (const fact of parsed.facts) {
      results.push({
        json: {
          entity_name: fact.entity_name || '',
          entity_type: fact.entity_type || 'concept',
          fact_details: fact.fact_details || '',
          confidence: fact.confidence || 0.8,
          source_table: parent.source_table,
          source_id: parent.id
        }
      });
    }
  }
}
return results;

const results = [];
const items = $input.all();
for (const item of items) {
  const parent = $('Get Unprocessed Staging').json;
  const responseText = item.json.response || item.json.content || '{}';
  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch(e) {
    parsed = { events: [] };
  }
  if (parsed.events && Array.isArray(parsed.events)) {
    for (const event of parsed.events) {
      results.push({
        json: {
          event_name: event.event_name || '',
          event_description: event.event_description || '',
          event_timestamp: event.event_timestamp || parent.event_time || new Date().toISOString(),
          actors: JSON.stringify(event.actors || []),
          outcome: event.outcome || '',
          source_table: parent.source_table,
          source_id: parent.id
        }
      });
    }
  }
}
return results;

